from __future__ import annotations

from dataclasses import dataclass
from datetime import datetime, timedelta
from typing import Optional


class OrderLifecycleError(ValueError):
    """Raised when an order lifecycle transition is invalid."""


@dataclass(frozen=True)
class CancellationWindow:
    minutes: int

    def __post_init__(self) -> None:
        if self.minutes < 0:
            raise ValueError("cancellation window minutes must be non-negative")

    def expires_at(self, placed_at: datetime, *, grace_minutes: int = 0) -> datetime:
        if grace_minutes < 0:
            raise ValueError("grace minutes must be non-negative")
        return placed_at + timedelta(minutes=self.minutes + grace_minutes)

    def is_expired(
        self,
        placed_at: datetime,
        requested_at: datetime,
        *,
        grace_minutes: int = 0,
    ) -> bool:
        return requested_at > self.expires_at(
            placed_at,
            grace_minutes=grace_minutes,
        )


@dataclass
class Order:
    id: str
    status: str
    placed_at: datetime
    payment_id: Optional[str] = None
    payment_status: str = "captured"
    customer_tier: str = "standard"
    cancelled_at: Optional[datetime] = None

    def can_cancel(self) -> bool:
        return self.status in {"pending", "paid", "processing"}

    def has_refund_hold(self) -> bool:
        return self.payment_status == "refund_hold"

    def cancel(self, cancelled_at: datetime) -> None:
        if not self.can_cancel():
            raise OrderLifecycleError(f"order {self.id} cannot be cancelled from {self.status}")
        if self.has_refund_hold():
            raise OrderLifecycleError(f"order {self.id} is on refund hold")

        self.status = "cancelled"
        self.cancelled_at = cancelled_at


__all__ = ["CancellationWindow", "Order", "OrderLifecycleError"]

