from dataclasses import dataclass
from datetime import datetime, timezone
from typing import Callable, Optional

from orders.order import CancellationWindow, Order
from orders.payment_adapter import PaymentAdapter, PaymentCancellationError

_PREMIUM_GRACE_MINUTES = 15


@dataclass(frozen=True)
class CancellationDecision:
    """Public cancellation outcome returned by the service."""

    allowed: bool
    reason: str
    order_id: str


class OrderCancellationService:
    """Use-case service that orchestrates cancellation checks and side effects."""

    def __init__(
        self,
        orders: object,
        payments: PaymentAdapter,
        cancellation_window: CancellationWindow,
        *,
        clock: Optional[Callable[[], datetime]] = None,
    ) -> None:
        self._orders = orders
        self._payments = payments
        self._cancellation_window = cancellation_window
        self._clock = clock or _utc_now

    def cancel(
        self,
        order_id: str,
        *,
        requested_at: Optional[datetime] = None,
    ) -> CancellationDecision:
        requested_at = requested_at or self._clock()
        order = self._orders.get(order_id)

        if not order.can_cancel():
            return _denied_decision(order, "not_cancellable")

        if self._cancellation_window.is_expired(
            order.placed_at,
            requested_at,
            grace_minutes=_premium_grace_minutes(order),
        ):
            return _denied_decision(order, "expired")

        if order.has_refund_hold():
            return _denied_decision(order, "refund_hold")

        if _has_payment_to_cancel(order):
            try:
                self._payments.cancel_payment(order.payment_id)
            except PaymentCancellationError:
                return _denied_decision(order, "payment_failed")

        order.cancel(requested_at)
        self._orders.save(order)

        return _allowed_decision(order)


def _utc_now() -> datetime:
    return datetime.now(timezone.utc)


def _premium_grace_minutes(order: Order) -> int:
    return _PREMIUM_GRACE_MINUTES if order.customer_tier == "premium" else 0


def _has_payment_to_cancel(order: Order) -> bool:
    return bool(order.payment_id)


def _denied_decision(order: Order, reason: str) -> CancellationDecision:
    return CancellationDecision(allowed=False, reason=reason, order_id=order.id)


def _allowed_decision(order: Order) -> CancellationDecision:
    return CancellationDecision(allowed=True, reason="cancelled", order_id=order.id)


__all__ = ["CancellationDecision", "OrderCancellationService"]

from __future__ import annotations


class PaymentCancellationError(RuntimeError):
    """Raised when the payment provider cannot cancel the payment side effect."""


class PaymentAdapter:
    """Adapter boundary for payment-provider cancellation side effects."""

    def __init__(self, provider: object) -> None:
        self._provider = provider

    def cancel_payment(self, payment_id: str) -> None:
        try:
            result = self._provider.cancel(payment_id)
        except Exception as exc:
            raise PaymentCancellationError("payment provider cancellation failed") from exc

        if result is False:
            raise PaymentCancellationError("payment provider rejected cancellation")


__all__ = ["PaymentAdapter", "PaymentCancellationError"]

